// 三载体一致:纯 JS 天文计算,零 DOM/CSS/uplink/shadow 足迹;v2 为命名导出(无 default)
import { getTimes, getPosition, getMoonIllumination, getMoonPosition, getMoonTimes } from 'https://cdn.jsdelivr.net/npm/suncalc@2/+esm';
const date = new Date(data.date), { lat, lng } = data;
const times = getTimes(date, lat, lng, data.height ?? 0); // {sunrise, sunset, goldenHour, …} Date|null
const sun = getPosition(date, lat, lng);                  // {azimuth, altitude} 单位:度、北基顺时针
const moon = getMoonIllumination(date);                   // {fraction, phase, angle, waxing}
